const body = $input.first().json.body ?? $input.first().json;

const ticket_id          = String(body.ticket_id          ?? '').trim();
const new_status         = String(body.new_status         ?? '').trim();
const internal_note      = String(body.internal_note      ?? '').trim() || null;
const estimated_ready_at = body.estimated_ready_at ?? null;
const price_final        = body.price_final !== undefined ? Number(body.price_final) : null;

const VALID_STATUSES = [
  'received','diagnosed','waiting_approval','in_repair',
  'waiting_parts','ready','delivered','cancelled'
];
const UUID_REGEX = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

if (!ticket_id) {
  return [{ json: { isValid: false, errorMessage: 'ticket_id est requis.' } }];
}
if (!UUID_REGEX.test(ticket_id)) {
  return [{ json: { isValid: false, errorMessage: 'ticket_id doit être un UUID valide.' } }];
}
if (!new_status) {
  return [{ json: { isValid: false, errorMessage: 'new_status est requis.' } }];
}
if (!VALID_STATUSES.includes(new_status)) {
  return [{ json: { isValid: false, errorMessage: `new_status invalide. Valeurs acceptées : ${VALID_STATUSES.join(', ')}` } }];
}
// price_final obligatoire quand le ticket passe à ready
if (new_status === 'ready' && (price_final === null || isNaN(price_final) || price_final < 0)) {
  return [{ json: { isValid: false, errorMessage: 'price_final est requis et doit être un nombre positif lorsque new_status = ready.' } }];
}

return [{
  json: {
    isValid: true,
    ticket_id,
    new_status,
    internal_note,
    estimated_ready_at,
    price_final
  }
}];

const payload   = $('Validate Payload').first().json;
const httpResp  = $input.first().json;

// Supabase retourne un tableau avec select
const tickets = Array.isArray(httpResp) ? httpResp : [httpResp];

if (!tickets.length || !tickets[0] || !tickets[0].id) {
  return [{ json: { errorCode: 404, errorMessage: `Ticket ${payload.ticket_id} introuvable.` } }];
}

const ticket  = tickets[0];
const contact = ticket.contacts ?? {};
const current_status = ticket.status;
const new_status     = payload.new_status;

// Matrice des transitions autorisées (unidirectionnelle, règle métier non négociable)
const ALLOWED = {
  received:         ['diagnosed', 'cancelled'],
  diagnosed:        ['waiting_approval', 'in_repair', 'cancelled'],
  waiting_approval: ['in_repair', 'cancelled'],
  in_repair:        ['waiting_parts', 'ready', 'cancelled'],
  waiting_parts:    ['in_repair', 'ready', 'cancelled'],
  ready:            ['delivered', 'cancelled'],
  delivered:        [],
  cancelled:        []
};

const allowed = ALLOWED[current_status] ?? [];
if (!allowed.includes(new_status)) {
  return [{
    json: {
      errorCode: 409,
      errorMessage: `Transition ${current_status} → ${new_status} non autorisée. Transitions possibles depuis '${current_status}' : ${allowed.length ? allowed.join(', ') : 'aucune'}.`
    }
  }];
}

// Données consolidées pour les étapes suivantes
return [{
  json: {
    errorCode:          null,
    ticket_id:          ticket.id,
    tracking_token:     ticket.tracking_token,
    current_status,
    new_status:         payload.new_status,
    internal_note:      payload.internal_note,
    estimated_ready_at: payload.estimated_ready_at,
    price_final:        payload.price_final,
    price_estimate:     ticket.price_estimate ?? null,
    contact_id:         contact.id   ?? null,
    contact_name:       contact.name ?? 'Client',
    contact_phone:      contact.phone ?? null,
    contact_email:      contact.email ?? null,
    device_brand:       ticket.device_brand ?? '',
    device_model:       ticket.device_model ?? ''
  }
}];

const data = $('Check Ticket + Validate Transition').first().json;
const {
  contact_name, contact_email,
  new_status, tracking_token,
  device_brand, device_model,
  price_final, price_estimate,
  estimated_ready_at
} = data;

const tracking_url = `${$env.APP_URL}/track/${tracking_token}`;
const review_url   = `${$env.APP_URL}/review/${tracking_token}`;

// Libellé lisible de l'appareil (sans accents pour SMS)
const device = [device_brand, device_model].filter(Boolean).join(' ') || 'votre appareil';
const price  = price_final ?? price_estimate ?? '–';
const estimated_date = estimated_ready_at
  ? new Date(estimated_ready_at).toLocaleDateString('fr-FR', { day: 'numeric', month: 'long', year: 'numeric' })
  : 'a confirmer';

let sms_content   = '';
let email_subject = '';
let email_html    = '';

const btnStyle = 'display:inline-block;background:#2563eb;color:#fff;padding:12px 24px;border-radius:6px;text-decoration:none;font-weight:bold;';

switch (new_status) {

  case 'diagnosed':
    sms_content   = `Bonjour ${contact_name}, le diagnostic de votre ${device} est termine. Devis : ${price} EUR. Validez sur : ${tracking_url}`;
    email_subject = 'Diagnostic terminé — votre accord est requis';
    email_html    = `<p>Bonjour ${contact_name},</p><p>Le diagnostic de votre <strong>${device}</strong> est terminé.</p><p><strong>Montant estimé : ${price} €</strong></p><p>Merci de valider ou de refuser la réparation depuis votre espace de suivi :</p><p><a href="${tracking_url}" style="${btnStyle}">Valider la réparation</a></p><p>L'équipe ReparFlow</p>`;
    break;

  case 'waiting_approval':
    sms_content   = `Rappel ReparFlow : votre devis pour ${device} est en attente de validation. Repondez ici : ${tracking_url}`;
    email_subject = 'Rappel — Votre devis attend votre réponse';
    email_html    = `<p>Bonjour ${contact_name},</p><p>Nous attendons toujours votre validation pour la réparation de votre <strong>${device}</strong>.</p><p>Sans réponse de votre part, le dossier sera mis en attente.</p><p><a href="${tracking_url}" style="${btnStyle}">Répondre maintenant</a></p><p>L'équipe ReparFlow</p>`;
    break;

  case 'in_repair':
    sms_content   = `Bonne nouvelle ! La reparation de votre ${device} a commence. Suivez l'avancement : ${tracking_url}`;
    email_subject = 'Réparation en cours';
    email_html    = `<p>Bonjour ${contact_name},</p><p>La réparation de votre <strong>${device}</strong> a démarré. Notre technicien s'en occupe.</p><p>Suivez l'avancement en temps réel :</p><p><a href="${tracking_url}">${tracking_url}</a></p><p>L'équipe ReparFlow</p>`;
    break;

  case 'waiting_parts':
    sms_content   = `Votre ${device} necessite une piece en commande. Delai estime : ${estimated_date}. Infos : ${tracking_url}`;
    email_subject = 'En attente d\'une pièce détachée';
    email_html    = `<p>Bonjour ${contact_name},</p><p>La réparation de votre <strong>${device}</strong> nécessite une pièce détachée actuellement en commande.</p><p><strong>Délai de réception estimé : ${estimated_date}</strong></p><p>Nous vous contacterons dès qu'elle sera reçue. Suivez votre dossier :</p><p><a href="${tracking_url}">${tracking_url}</a></p><p>L'équipe ReparFlow</p>`;
    break;

  case 'ready':
    sms_content   = `Votre ${device} est repare et pret a etre recupere ! Montant : ${price_final} EUR. Infos : ${tracking_url}`;
    email_subject = 'Votre appareil est prêt !';
    email_html    = `<p>Bonjour ${contact_name},</p><p>Excellente nouvelle ! Votre <strong>${device}</strong> est réparé et vous attend à l'atelier.</p><p><strong>Montant à régler : ${price_final} €</strong></p><hr style="margin:20px 0;"><p><strong>Retrouvez-nous à :</strong><br>123 rue de la Réparation, 75001 Paris<br>Lun – Sam : 9h00 – 19h00</p><hr style="margin:20px 0;"><p><a href="${tracking_url}" style="${btnStyle}">Voir mon dossier</a></p><p>L'équipe ReparFlow</p>`;
    break;

  case 'delivered':
    sms_content   = `Merci pour votre confiance ReparFlow ! Votre avis nous aide : ${review_url}`;
    email_subject = 'Merci — Donnez-nous votre avis !';
    email_html    = `<p>Bonjour ${contact_name},</p><p>Merci d'avoir fait confiance à ReparFlow pour la réparation de votre <strong>${device}</strong>. Nous espérons que vous êtes satisfait(e) !</p><p>Votre avis est précieux et aide d'autres clients à nous trouver :</p><p><a href="${review_url}" style="${btnStyle}">Laisser un avis</a></p><p>À bientôt !</p><p>L'équipe ReparFlow</p>`;
    break;

  case 'cancelled':
    sms_content   = `Votre dossier ReparFlow (${device}) a ete clos. Pour toute question, contactez notre atelier.`;
    email_subject = 'Votre dossier a été clôturé';
    email_html    = `<p>Bonjour ${contact_name},</p><p>Votre dossier de réparation pour votre <strong>${device}</strong> a été clôturé.</p><p>Si vous avez des questions ou souhaitez ouvrir un nouveau dossier, n'hésitez pas à nous contacter.</p><p>L'équipe ReparFlow</p>`;
    break;

  default:
    sms_content   = `Mise a jour de votre dossier ReparFlow. Suivez l'avancement : ${tracking_url}`;
    email_subject = 'Mise à jour de votre dossier';
    email_html    = `<p>Bonjour ${contact_name},</p><p>Votre dossier a été mis à jour. Consultez votre espace de suivi :</p><p><a href="${tracking_url}">${tracking_url}</a></p><p>L'équipe ReparFlow</p>`;
}

return [{
  json: {
    ...data,
    tracking_url,
    review_url,
    sms_content,
    email_subject,
    email_html
  }
}];

// Récupère les données enrichies depuis Build Notification Content
const data = $('Build Notification Content').first().json;

// L'email a été envoyé si contact_email était renseigné
const notifications_sent = ['sms'];
if (data.contact_email) {
  notifications_sent.push('email');
}

return [{
  json: {
    success:            true,
    ticket_id:          data.ticket_id,
    old_status:         data.current_status,
    new_status:         data.new_status,
    notifications_sent
  }
}];
